STATIC int
xfs_iget_recycle(
	struct xfs_perag	*pag,
	struct xfs_inode	*ip)
{
	trace_xfs_iget_recycle(ip);

	/*
	 * We need to set XFS_IRECLAIM to prevent xfs_iget_cache_hit
	 * from finding this inode.  Then we can drop the i_flags_lock
	 * as xfs_ireclaim() will acquire it again to modify the flags.
	 */
	ip->i_flags |= XFS_IRECLAIM;
	spin_unlock(&ip->i_flags_lock);
	rcu_read_unlock();

	error = xfs_ireclaim(pag, ip);
	if (error) {
		/*
		 * If we can't reclaim, clear the reclaim flag and return
		 * the error.  The inode may be in a state where it can't
		 * be reclaimed (e.g. due to being in the process of
		 * being reclaimed by another thread).  We return -EAGAIN
		 * so the caller will retry.
		 */
		spin_lock(&ip->i_flags_lock);
		ip->i_flags &= ~XFS_IRECLAIM;
		spin_unlock(&ip->i_flags_lock);
		return error;
	}

	/* 成功 */
	XFS_STATS_INC(mp, xs_ig_frecycle);
	return 0;
}

