xlog_recover_iget_handle(
    struct xfs_mount    *mp,
    xfs_ino_t       ino,
    uint32_t        gen,
    struct xfs_inode    **ipp)
{
    struct xfs_inode    *ip;
    int         error;

    error = xlog_recover_iget(mp, ino, &ip);
    if (error)
        return error;

    if (VFS_I(ip)->i_generation != gen) {
