```c
int
xlog_recover_iget(
    struct xfs_mount    *mp,
    xfs_ino_t       ino,
    struct xfs_inode    **ipp)
{
    int         error;

    error = xfs_iget(mp, NULL, ino, 0, 0, ipp);
    if (error)
        return error;

    error = xfs_qm_dqattach(*ipp);
    if (error) {
        xfs_irele(*ipp);
        return error;
    }

    if (VFS_I(*ipp)->i_nlink == 0)
        xfs_iflags_set(*ipp, XFS_IRECOVERY);

    return 0;
}
```

